import React, { useState, useRef, useEffect } from 'react';
import './Sidebar.css';
import { Home, Folder, Users, Moon, Sparkles, Settings } from 'lucide-react';
import { useDesignSystem } from '../designSystem/DesignSystemContext';

const Sidebar: React.FC = () => {
  const { designSystem } = useDesignSystem();
  const [showSettingsMenu, setShowSettingsMenu] = useState(false);
  const settingsBtnRef = useRef<HTMLButtonElement>(null);
  const menuRef = useRef<HTMLDivElement>(null);

  // Close menu on outside click
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (
        menuRef.current &&
        !menuRef.current.contains(event.target as Node) &&
        settingsBtnRef.current &&
        !settingsBtnRef.current.contains(event.target as Node)
      ) {
        setShowSettingsMenu(false);
      }
    };
    if (showSettingsMenu) {
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
    }
  }, [showSettingsMenu]);

  return (
    <div
      className="sidebar"
      style={{
        background: designSystem.colors.surface,
        fontFamily: designSystem.font.family,
        color: designSystem.colors.text,
        borderRight: `1px solid ${designSystem.colors.border}`,
      }}
    >
      {/* Logo */}
      <div className="logo">
        <img
          src="/figaroo-logo.png"
          alt="Figaroo Logo"
          className="figaroo-logo-img"
          style={{
            filter: `drop-shadow(0 2px 8px ${designSystem.colors.black}20)`
          }}
        />
      </div>

      {/* User Profile */}
      <div className="user-profile">
        <div className="user-avatar">
          <Sparkles size={16} />
        </div>
        <span className="user-name">Ali Shan</span>
        <button className="dropdown-btn">▼</button>
      </div>

      {/* Navigation */}
      <nav className="nav">
        <a href="#" className="nav-item active">
          <Home className="nav-icon" size={18} />
          <span>Home</span>
        </a>
        <a href="#" className="nav-item">
          <Folder className="nav-icon" size={18} />
          <span>My Files</span>
        </a>
        <a href="#" className="nav-item">
          <Users className="nav-icon" size={18} />
          <span>Shared with Me</span>
        </a>
      </nav>

      {/* Components Counter */}
      <div className="components-counter">
        <div className="counter-bar">
          <div className="counter-fill" style={{ width: '60%' }}></div>
        </div>
        <span className="counter-text">3/5 Components used</span>
      </div>

      {/* Theme and Settings Toggle */}
      <div className="bottom-buttons">
        <button className="theme-toggle" title="Toggle Theme">
          <Moon size={18} />
        </button>
        <button
          className="settings-btn"
          title="Settings"
          ref={settingsBtnRef}
          onClick={() => setShowSettingsMenu((v) => !v)}
        >
          <Settings size={18} />
          <span>Settings</span>
        </button>
        {showSettingsMenu && (
          <div className="settings-menu glassy-menu" ref={menuRef}>
            <button className="glassy-menu-item" onClick={() => setShowSettingsMenu(false)}>
              Privacy Policy
            </button>
            <button className="glassy-menu-item" onClick={() => setShowSettingsMenu(false)}>
              Help &amp; Support
            </button>
            <button className="glassy-menu-item" onClick={() => setShowSettingsMenu(false)}>
              Cookie Policy
            </button>
            <button className="glassy-menu-item" onClick={() => setShowSettingsMenu(false)}>
              Terms of Service
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Sidebar;
